import { ConfigContext } from "../config.js";
import { ServerPlugin } from "../lib/types.js";
import { FC } from "react";
import { AsyncAPIPageProps } from "@fumadocs/asyncapi/ui";
import { AsyncAPIServer } from "@fumadocs/asyncapi/server";
//#region src/plugins/asyncapi.d.ts
interface OpenAPIOptions {
  server: AsyncAPIServer;
  /** do not add the loader plugin for OpenAPI integration */
  disableLoaderPlugin?: boolean;
  /** must be a client component */
  ClientAPIPage?: FC<AsyncAPIPageProps>;
}
/**
 * this will register the OpenAPI adapter & required layout configs.
 */
declare function asyncapiPlugin<C extends ConfigContext>(options: OpenAPIOptions): ServerPlugin<C>;
//#endregion
export { OpenAPIOptions, asyncapiPlugin };